_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

//ret=GetPixel(vUvOriginal+uTexSize.zw*vec2(q6,q7));
vec2 newuv=vUv;
ret=GetPixel(newuv);
vec3 lum1=0,lum2=0,lum3=0,lum4=0,lum5=0,lum6=0,lum7=0,lum8=0;
vec3 mxv=0;
float r=8;
//Blur1: r=4 (pixels);
//Blur2: r=8 (pixels);
//Blur3: r=9 (pixels);
float ro=0.707106*r;
uTexSize.zw*r;
lum1=GetBlur2(newuv+uTexSize.zw*vec2(1,0));
lum2=GetBlur2(newuv+uTexSize.zw*vec2(0,1));
lum3=GetBlur2(newuv+uTexSize.zw*vec2(-1,0));
lum4=GetBlur2(newuv+uTexSize.zw*vec2(0,-1));
lum5=GetBlur2(newuv+uTexSize.zw*vec2(ro,-ro));
lum6=GetBlur2(newuv+uTexSize.zw*vec2(-ro,ro));
lum7=GetBlur2(newuv+uTexSize.zw*vec2(ro,ro));
lum8=GetBlur2(newuv+uTexSize.zw*vec2(-ro,-ro));
mxv=abs(lum1-lum2+lum3-lum4+lum5-lum6+lum7-lum8)*0.5;
ret*=mxv+0.99;
ret=ret-mxv*2+0.1+0.1*(0.15-texture(sampler_noise_lq,vUv*rand_frame.xy*9))-0.1*GetBlur1(vUv);

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv2;
float ang2, c, s;
vUv -= 0.5;
vUv *= uAspect.xy;

float dist = 1;
float inten = 1;
ret1 = 0;
int anz = 3;
int n = 1;
while (n <= anz) {
    ang2 = n/anz;
    c = (ang2);
    s = 1-(ang2);
    uv2.x =  vUv.x*c - vUv.y*s;
    uv2.y =  vUv.x*s + vUv.y*c;
    uv2 *= uAspect.yx;
    dist = 1-fract(.25*n+q29); //evtl sqrt !
    inten =  pow(dist,.5)*(1-dist*dist)*2;
    vec2 uv3 = fract(3*uv2*dist + .5 + q31);;
//use in warp shader for collidescope in neon 3 mixes
uv3=abs(fract(uv3+.5)-.5) ;

    neu =  GetPixel (uv3) + 2*GetBlur1(uv3);

    ret1 = max(ret1*.9,neu*inten);
n++;
}

ret = .5*ret1 + 0.5*vec3(0,0,.3)*(.5+vUv.y) ;
//ret = GetPixel(vUv+.5);

  fragColor = ret;
}
